class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        window = UIWindow(windowScene: windowScene)
        let rootVC = HomeViewController() // Your initial root view controller
        window?.rootViewController = UINavigationController(rootViewController: rootVC)
        window?.makeKeyAndVisible()

        if let userActivity = connectionOptions.userActivities.first(where: { $0.activityType == NSUserActivityTypeBrowsingWeb }),
           let incomingURL = userActivity.webpageURL {
            handleUniversalLink(incomingURL)
        }
    }

    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return
        }
        handleUniversalLink(incomingURL)
    }

    private func handleUniversalLink(_ url: URL) {
        guard url.scheme == "https", url.host == "myapp.com" else {
            // Optionally open in Safari if it's not our expected host
            if UIApplication.shared.canOpenURL(url) {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
            }
            return
        }

        print("Received universal link: \(url.absoluteString)")

        // Ensure we have a navigation controller to push onto
        guard let navigationController = window?.rootViewController as? UINavigationController else {
            print("Error: Root view controller is not a UINavigationController.")
            // You might want to reset to a known state or show an alert here
            return
        }

        // Pop to root before navigating to ensure a clean stack
        navigationController.popToRootViewController(animated: false)

        let pathComponents = url.pathComponents.filter { !$0.isEmpty } // Remove leading "/" and empty components

        guard let firstPathComponent = pathComponents.first else {
            // Handle base URL, e.g., https://myapp.com/
            print("Navigating to home from base URL.")
            // No specific action needed if already at root
            return
        }

        switch firstPathComponent {
        case "profile":
            if pathComponents.count > 1, let profileID = pathComponents[1] {
                print("Navigating to Profile with ID: \(profileID)")
                let profileVC = ProfileViewController(profileID: profileID)
                navigationController.pushViewController(profileVC, animated: true)
            } else {
                print("Navigating to general Profile view (no ID specified).")
                let profileVC = ProfileViewController(profileID: nil)
                navigationController.pushViewController(profileVC, animated: true)
            }
        case "payment":
            if pathComponents.count > 1, pathComponents[1] == "confirm" {
                print("Navigating to Payment Confirmation.")
                let paymentConfirmVC = PaymentConfirmViewController()
                navigationController.pushViewController(paymentConfirmVC, animated: true)
            } else {
                print("Navigating to general Payment view.")
                let paymentVC = PaymentViewController()
                navigationController.pushViewController(paymentVC, animated: true)
            }
        case "admin":
            if pathComponents.count > 1, pathComponents[1] == "settings" {
                print("Navigating to Admin Settings.")
                let adminSettingsVC = AdminSettingsViewController()
                navigationController.pushViewController(adminSettingsVC, animated: true)
            } else {
                print("Navigating to general Admin view.")
                let adminVC = AdminViewController()
                navigationController.pushViewController(adminVC, animated: true)
            }
        default:
            print("Unknown path component: \(firstPathComponent). Navigating to home.")
            // Optionally, you could show an alert or a generic error page
            break // Already at root, no specific action
        }
    }

    // Other SceneDelegate methods...
    func sceneDidDisconnect(_ scene: UIScene) {}
    func sceneDidBecomeActive(_ scene: UIScene) {}
    func sceneWillResignActive(_ scene: UIScene) {}
